use crate::{fat32,handle::HandleError,process::{Process,ProcessState,SuspendedCall},process_table,serial};
pub const ABI_VERSION:u64=1;pub const SYS_WRITE:u64=1;pub const SYS_EXIT:u64=2;pub const SYS_SLEEP:u64=3;pub const SYS_WAIT:u64=4;pub const SYS_GETPID:u64=5;pub const SYS_OPEN:u64=6;pub const SYS_READ:u64=7;pub const SYS_CLOSE:u64=8;pub const SYS_STAT:u64=9;const MAX_WRITE:usize=256;const MAX_READ:usize=256;const MAX_PATH:usize=64;
#[derive(Clone,Copy,Debug,PartialEq,Eq)]#[repr(i64)]pub enum Errno{Invalid=1,BadAddress=2,TooLarge=3,NotSupported=4,NoSuchProcess=5,NotChild=6,Busy=7,NoSuchFile=8,BadHandle=9,TooManyOpen=10}impl Errno{pub const fn encoded(self)->u64{(-(self as i64))as u64}}
#[derive(Clone,Copy,Debug,PartialEq,Eq)]pub enum SyscallAction{Return,Terminate,Suspend(SuspendedCall)}#[derive(Clone,Copy,Debug,PartialEq,Eq)]pub struct SyscallResult{pub value:u64,pub action:SyscallAction}impl SyscallResult{const fn ok(v:u64)->Self{Self{value:v,action:SyscallAction::Return}}const fn error(e:Errno)->Self{Self{value:e.encoded(),action:SyscallAction::Return}}const fn suspend(c:SuspendedCall)->Self{Self{value:0,action:SyscallAction::Suspend(c)}}}
pub fn dispatch(p:&mut Process,n:u64,a:[u64;6])->SyscallResult{match n{SYS_WRITE=>write(p,a[0],a[1]),SYS_EXIT=>{let c=a[0]as i32;p.exit(c);let _=process_table::exit(p.pid,c);process_table::orphan_children(p.pid);SyscallResult{value:0,action:SyscallAction::Terminate}},SYS_SLEEP=>{let now=a[1];let Some(d)=now.checked_add(a[0])else{return SyscallResult::error(Errno::Invalid)};if process_table::sleep_until(p.pid,now,d).is_err(){return SyscallResult::error(Errno::Invalid)}p.state=ProcessState::Sleeping;SyscallResult::suspend(SuspendedCall::Sleep)},SYS_WAIT=>match process_table::wait_blocking(p.pid,a[0]){Ok(Some(s))=>SyscallResult::ok(s as u32 as u64),Ok(None)=>{p.state=ProcessState::Sleeping;SyscallResult::suspend(SuspendedCall::Wait{child:a[0]})},Err(e)=>SyscallResult::error(table_errno(e))},SYS_GETPID=>SyscallResult::ok(p.pid),SYS_OPEN=>open(p,a[0],a[1]),SYS_READ=>read(p,a[0],a[1],a[2]),SYS_CLOSE=>close(p,a[0]),SYS_STAT=>stat(p,a[0],a[1],a[2]),_=>SyscallResult::error(Errno::NotSupported)}}
fn table_errno(e:process_table::TableError)->Errno{match e{process_table::TableError::NoSuchProcess=>Errno::NoSuchProcess,process_table::TableError::NotChild=>Errno::NotChild,process_table::TableError::StillRunning=>Errno::Busy,_=>Errno::Invalid}}fn handle_errno(e:HandleError)->Errno{match e{HandleError::NotMounted=>Errno::NotSupported,HandleError::NotFound=>Errno::NoSuchFile,HandleError::TooManyOpen=>Errno::TooManyOpen,HandleError::BadHandle=>Errno::BadHandle}}
fn write(p:&Process,address:u64,length:u64)->SyscallResult{let Ok(l)=usize::try_from(length)else{return SyscallResult::error(Errno::TooLarge)};if l>MAX_WRITE{return SyscallResult::error(Errno::TooLarge)}let mut b=[0u8;MAX_WRITE];if p.address_space.copy_from_user(&mut b[..l],address).is_err(){return SyscallResult::error(Errno::BadAddress)}serial::info(format_args!("user[{}] write {} bytes",p.pid,l));SyscallResult::ok(l as u64)}fn path(p:&Process,address:u64,length:u64)->Result<([u8;MAX_PATH],usize),SyscallResult>{let Ok(l)=usize::try_from(length)else{return Err(SyscallResult::error(Errno::Invalid))};if l==0||l>MAX_PATH{return Err(SyscallResult::error(Errno::Invalid))}let mut b=[0u8;MAX_PATH];if p.address_space.copy_from_user(&mut b[..l],address).is_err(){return Err(SyscallResult::error(Errno::BadAddress))}Ok((b,l))}fn open(p:&mut Process,address:u64,length:u64)->SyscallResult{let(b,l)=match path(p,address,length){Ok(v)=>v,Err(e)=>return e};match p.handle_table.open(&b[..l]){Ok(fd)=>SyscallResult::ok(fd as u64),Err(e)=>SyscallResult::error(handle_errno(e))}}fn read(p:&mut Process,fd:u64,address:u64,length:u64)->SyscallResult{let Ok(fd)=usize::try_from(fd)else{return SyscallResult::error(Errno::BadHandle)};let Ok(l)=usize::try_from(length)else{return SyscallResult::error(Errno::TooLarge)};let l=l.min(MAX_READ);let mut b=[0u8;MAX_READ];let n=match p.handle_table.read(fd,&mut b[..l]){Ok(n)=>n,Err(e)=>return SyscallResult::error(handle_errno(e))};if n>0&&p.address_space.copy_to_user(address,&b[..n]).is_err(){return SyscallResult::error(Errno::BadAddress)}SyscallResult::ok(n as u64)}fn close(p:&mut Process,fd:u64)->SyscallResult{let Ok(fd)=usize::try_from(fd)else{return SyscallResult::error(Errno::BadHandle)};match p.handle_table.close(fd){Ok(())=>SyscallResult::ok(0),Err(e)=>SyscallResult::error(handle_errno(e))}}fn stat(p:&Process,address:u64,length:u64,out:u64)->SyscallResult{let(b,l)=match path(p,address,length){Ok(v)=>v,Err(e)=>return e};let Some(loc)=fat32::lookup(&b[..l])else{return SyscallResult::error(Errno::NoSuchFile)};if p.address_space.copy_to_user(out,&(loc.size as u64).to_le_bytes()).is_err(){return SyscallResult::error(Errno::BadAddress)}SyscallResult::ok(0)}
